sql:
SELECT COUNT(DISTINCT e.customer_id) AS total_customers_received_campaign
FROM customer_email_interactions e
WHERE e.email_received = 1 AND e.email_campaign_id = 0;

external_knowledge:
- 'navigators' refers to customers;
- 'Summer Sale voyage' refers to the 'Summer Sale' email campaign;
- 'embarked on the journey' means the customers are part of a segment related to Summer Sale;
- 'ventured beyond the initial port by clicking the beacon' means the customers clicked on the link in the email.

sql:
SELECT DISTINCT c.email
FROM customers c
JOIN customer_email_interactions cei ON c.id = cei.customer_id;

SELECT COUNT(DISTINCT customer_id) AS active_customers
FROM customer_email_interactions
WHERE date >= DATE('now', '-30 days');

SELECT * 
FROM email_campaigns 
WHERE name = 'Summer Sale';
